import android.content.Context
import android.content.SharedPreferences

class AuthenticationManager(private val context: Context) {

    private val preferences: SharedPreferences = context.getSharedPreferences("auth", Context.MODE_PRIVATE)

    fun saveAuthToken(authToken: String, userId: String): Boolean {
        return try {
            preferences.edit().putString("auth_token", authToken).apply()
            preferences.edit().putString("user_id", userId).apply()
            true
        } catch (e: Exception) {
            false
        }
    }

    fun getAuthToken(): String? = preferences.getString("auth_token", null)

    fun getUserId(): String? = preferences.getString("user_id", null)

    fun removeAuthentication() {
        preferences.edit().clear().apply()
    }
}